import{_ as e,c as t,o as r,a}from"./app.27340559.js";const b=JSON.parse('{"title":"","description":"","frontmatter":{},"headers":[{"level":2,"title":"esbuild","slug":"esbuild","link":"#esbuild","children":[]},{"level":2,"title":"浏览器插件","slug":"浏览器插件","link":"#浏览器插件","children":[]}],"relativePath":"week/202111-1.md"}'),s={name:"week/202111-1.md"},o=a('<h2 id="esbuild" tabindex="-1">esbuild <a class="header-anchor" href="#esbuild" aria-hidden="true">#</a></h2><p><a href="https://esbuild.docschina.org/" target="_blank" rel="noreferrer">esbuild</a>是<code>GO语言</code>编写的前端打包工具 跟<code>webpack</code>、<code>rollup</code>、<code>vite</code>属于同类工具库</p><p>以前传统打包工具webpack、rollup都是使用js编写的</p><p><strong>vite就是基于esbuild的打包工具</strong>，通过换一种底层语言实现优化打包的性能，直接绕过js的局限 如：单线程不能并行、打包工具本身需要解析、读取AST次数导致的内存没有合理实现... (传统js语言打包工具，在执行打包时需要先解析js成底层语言，才能开始打包。而GO更接近底层语言解析速度更快)</p><p>另外esbuild原生支持编译typescript、压缩代码、tree-shaking <a href="https://zhuanlan.zhihu.com/p/379164359" target="_blank" rel="noreferrer">ESbuild为什么这么快</a></p><h2 id="浏览器插件" tabindex="-1">浏览器插件 <a class="header-anchor" href="#浏览器插件" aria-hidden="true">#</a></h2><p><a href="https://github.com/betterRunner/context-note" target="_blank" rel="noreferrer">context-note</a> 一个 Chrome 浏览器插件，可以对网页做笔记，下次打开该网页，笔记就会显示，并提供富文本编辑器和笔记标签。</p>',7),n=[o];function d(i,l,c,h,p,_){return r(),t("div",null,n)}const f=e(s,[["render",d]]);export{b as __pageData,f as default};
